      "keystrokes": "objdump -d /app/mystery > /tmp/disasm.txt; wc -l /tmp/disasm.txt; grep -n '^0000000000402' /tmp/disasm.txt | head -80\n",
      "duration": 1.0
    },
    {
      "keystrokes": "sed -n '/<main>:/,/^0000000000402/p' /tmp/disasm.txt | wc -l\n",
